head.script:
scwin.odrLineNo = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // 파라미터 SET
    var params = $c.data.getParameter();
    if (!$c.util.isEmpty(params["odrLineNo"])) {
        scwin.odrLineNo = params["odrLineNo"];
    }

    // SD463 공통코드 데이터 없음(OP228인데 잘못쓴거 같음) 콤보박스 바인딩되지않고 조회된 데이터 그대로 뿌려지기 때문에 inputType=text로 변경
    const codeOptions = [
        { grpCd: "OP228", compID: "gr_InvoiceInfo:ioClsCd" } //구분
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_SetGridColumnMaxLength(gr_InvoiceInfo); // 그리드 maxlength 설정
};

//-------------------------------------------------------------------------
// 입력 그리드 maxlength 설정
//-------------------------------------------------------------------------
scwin.f_SetGridColumnMaxLength = function (gridViewObj) {
    for (let i = 0; i < gridViewObj.getTotalCol(); i++) {
        let colNm = gridViewObj.getColumnID(i);
        let dataObj = $c.gus.object(gridViewObj.getDataList());
        let colInfo = dataObj.getColumnInfo(colNm);

        if (typeof colInfo != "undefined") {
            gridViewObj.setMaxLength(i, colInfo.length);
        }
    }
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
        //소스
        var dateStr = $c.date.getServerDateTime("yyyyMMdd"); //현재일자
        ica_transferDt.setValue(dateStr);
        ed_outDtFrom.setValue(dateStr.substring(0, 6) + '01');
        ed_outDtTo.setValue(dateStr);

        scwin.f_defaultValue();

        //테스트 데이터
        // ds_Query.set("outDtFrom", "20240801");
        // ds_Query.set("outDtTo", "20240831");

    }, { "delay": 50 });
};

//-------------------------------------------------------------------------
// 기본값 설정
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
    ed_clntNo.setValue("253811");
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), 'T', 'T');

    scwin.f_Retrieve("odrLine");
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function (odrLine) {
    if (odrLine == "odrLine") {
        if (!$c.gus.cfIsNull(scwin.odrLineNo) && 'null' != scwin.odrLineNo) {
            ed_outDtFrom.setValue("");
            ed_outDtTo.setValue("");
            udc_odrLineNo.setData(scwin.odrLineNo);     

            $c.sbm.execute(sbm_retrieve);
        }
    } else {
        if ($c.gus.cfIsNull(ed_clntNo.getValue())) {
            $c.gus.cfAlertMsg("거래처를 입력하십시오.");
            ed_clntNo.focus();
            return;
        }
        if (($c.gus.cfIsNull(ed_outDtFrom.getValue()) && $c.gus.cfIsNull(ed_outDtTo.getValue())) && ($c.gus.cfIsNull(ed_outDtFrom.getValue()) || $c.gus.cfIsNull(ed_outDtTo.getValue()))) {
            $c.gus.cfAlertMsg("재고이관일자를 입력하십시오.");
            ed_clntNo.focus();
            return;
        }
        if (!$c.gus.cfIsAfterDate(ed_outDtFrom.getValue(), ed_outDtTo.getValue())) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
            ed_outDtFrom.focus();
            return;
        }

        $c.sbm.execute(sbm_retrieve);
    }
};

//-------------------------------------------------------------------------
// 이관등록
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    var cnt = 0;

    if ($c.gus.cfIsNull(ica_transferDt.getValue())) {
        $c.win.alert("이관일자를 선택해주세요.");
        return;
    }

    for (var i = 0; i < ds_InvoiceInfo.getRowCount(); i++) {
        if (ds_InvoiceInfo.getCellData(i, "chk") == "T" || ds_InvoiceInfo.getRowStatus(i) == "U") {
            ds_InvoiceInfo.setCellData(i, "transferDt", ica_transferDt.getValue());

            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("항목을 선택해주세요.");
        return;
    }
};

//-------------------------------------------------------------------------
// 이관취소
//------------------------------------------------------------------------- 
scwin.f_CancelUpdate = function () {
    var cnt = 0;

    for (var i = 0; i < ds_InvoiceInfo.getRowCount(); i++) {
        if (ds_InvoiceInfo.getCellData(i, "chk") == "T") {
            ds_InvoiceInfo.setCellData(i, "transferDt", "");

            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("항목을 선택해주세요.");
        return;
    }
};

//------------------------------------
// 취소
//------------------------------------
scwin.f_cancel = async function () {
    var cnt = 0;

    for (var i = 0; i < ds_InvoiceInfo.getRowCount(); i++) {
        if (ds_InvoiceInfo.getCellData(i, "chk") == "T") {
            ds_InvoiceInfo.setCellData(i, "transferDt", "");
            ds_InvoiceInfo.setCellData(i, "names", "(주)포스코인터내셔널");

            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("취소할 항목을 선택해 주세요.");
        return;
    }

    //취소 여부 확인
    let ret = await $c.win.confirm(MSG_CM_CRM_011); // 취소 하시겠습니까?
    if (ret) {
        $c.sbm.execute(sbm_save);
    }

};

//------------------------------------
// 저장
//------------------------------------
scwin.f_Save = async function () {
    var cnt = 0;

    for (var i = 0; i < ds_InvoiceInfo.getRowCount(); i++) {
        if (ds_InvoiceInfo.getCellData(i, "chk") == "T") {
            cnt++;
        }
    }

    if (cnt == 0) {
        $c.win.alert("저장할 항목을 선택해 주세요.");
        return;
    }

    //저장 여부 확인
    let ret = await $c.win.confirm(MSG_CM_CRM_001); // 저장 하시겠습니까?
    if (ret) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function () {
    var totCnt = ds_InvoiceInfo.getRowCount();
    var sheetTitle = "포스코 하치장재고판매 ";

    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            const options = {
                fileName: sheetTitle + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                , sheetName: sheetTitle //엑셀내 시트명 지정필요시
            };

            const infoArr = [];

            $c.data.downloadGridViewExcel(gr_InvoiceInfo, options, infoArr);
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1:
            // 거래처 팝업
            udc_clntNo.setSelectId("retrieveClntInfo2"); // XML상의 SELECT ID
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                , pCode // 화면에서의 ??? Code Element의 Value
                , pName // 화면에서의 ??? Name Element의 Value
                , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
                , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                , null // Title순서
                , null // 보여주는 각 컬럼들의 폭
                , null // 컬럼중에서 숨기는 컬럼 지정
                , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                , null // POP-UP뛰을때 원도우의 사용자 정의 폭
                , null // POP-UP뛰을때 우도우의 사용자 정의 높이
                , null // 윈도우 위치 Y좌표
                , null // 윈도우 위치 X좌표
                , null // 중복체크여부 ("F")
                , pAllSearch // 전체검색허용여부 ("F")
                , "계약 거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// GRID에서 선택된 오더요청처리 : 해당 오더요청처리 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_srchCond);

    ed_clntNo.focus();
};


//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_InvoiceInfo.getRowCount() == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
    }

    tbx_totalRows.setValue(ds_InvoiceInfo.getRowCount()); // 소계 부분을 뺀 실제 데이터 갯수를 Count...

};

//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);

    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 화주 UDC START
//-------------------------------------------------------------------------
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), ed_clntNm.getValue(), 'F', 'F');
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, ed_clntNm, 1);
};

scwin.udc_clntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_clntNm, ed_clntNo, 1, false);
};

scwin.udc_clntNo_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_clntNo, ed_clntNm);
};
//-------------------------------------------------------------------------
// 화주 UDC END
//-------------------------------------------------------------------------
